import{_ as t,o as n,c as a,a8 as o}from"./chunks/framework.DvHWw5tv.js";const u=JSON.parse('{"title":"About Mengyue Components","description":"","frontmatter":{"layout":"home","title":"About Mengyue Components","hero":{"name":"Mengyue Components","tagline":"From 0 to 1—not through team effort, but through passion and persistence.","actions":[{"theme":"brand","text":"Start Exploring →","link":"/components/FastStart"}]}},"headers":[],"relativePath":"en/about/index.md","filePath":"en/about/index.md"}'),i={name:"en/about/index.md"};function s(r,e,d,l,c,p){return n(),a("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1776104037000"},[...e[0]||(e[0]=[o('<section class="about-container" data-v-587f5053><h2 data-v-587f5053>💫 Origin</h2><p data-v-587f5053><strong data-v-587f5053>Mengyue Components</strong> has no team, no funding, and no predefined roadmap. It began as a personal journey—a developer&#39;s exploration to build a modern component system from scratch. </p><p data-v-587f5053> Every component, animation, and line of logic was meticulously crafted during late-night hours. From architectural considerations to interaction design, from styling details to performance optimization, each iteration represents a milestone in personal growth. While some components may still have room for improvement, continuous refinement ensures every feature and API evolves toward perfection. </p><h2 data-v-587f5053>🧩 Philosophy</h2><p data-v-587f5053> This component library isn&#39;t about showcasing technical prowess, but rather finding an elegant balance— <em data-v-587f5053>bringing order to code, naturalness to interactions, and lightness to development.</em></p><p data-v-587f5053> Therefore, significant time has been dedicated to contemplating: </p><ul data-v-587f5053><li data-v-587f5053>How to make component logic more concise and reusable?</li><li data-v-587f5053>How to create a styling system that&#39;s both flexible and consistent?</li><li data-v-587f5053>How to minimize bundle size and accelerate loading performance?</li><li data-v-587f5053>How to make documentation more intuitive and accessible?</li><li data-v-587f5053>How to maintain simplicity while ensuring universal applicability across diverse needs?</li></ul><h2 data-v-587f5053>🚀 From 0 to 1</h2><p data-v-587f5053> From the very first button to a complete build system with automated deployment pipelines, every detail of <strong data-v-587f5053>Mengyue Components</strong> embodies thoughtful practice and reflection. </p><p data-v-587f5053> Without team collaboration, UI designers, or dedicated QA engineers, all aspects—including design, coding, documentation, testing, bundling, and publishing—were accomplished independently. This journey represents not just technical exploration, but also a testament to patience, aesthetic sensibility, and genuine passion. </p><h2 data-v-587f5053>🌈 Vision</h2><p data-v-587f5053> While there are undoubtedly areas for improvement, <strong data-v-587f5053>Mengyue Components</strong> will continue evolving. We hope it becomes a starting point for developers to learn from, draw inspiration from, and eventually contribute to— growing through community engagement and maturing through collective experience. </p><p class="thanks" data-v-587f5053> Finally, thank you for every click and visit. </p></section>',1)])])}const f=t(i,[["render",s],["__scopeId","data-v-587f5053"]]);export{u as __pageData,f as default};
